import pytest
import torch
import ttnn
import torch.nn.functional

from .layer_norm_rm import layer_norm_rm


def pytorch_reference(input_tensor, gamma, beta):
    """PyTorch reference for this stage."""
    return torch.nn.functional.layer_norm(
        input_tensor, [input_tensor.shape[-1]], weight=gamma.squeeze(), bias=beta.squeeze(), eps=1e-5
    )


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((4, 2, 64, 64), id="4x2x64x64"),
    ],
)
def test_affine_transform(device, shape):
    """Verify layer norm with affine transform (gamma and beta)."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    gamma = torch.randn(1, 1, 1, torch_input.shape[-1])
    beta = torch.randn(1, 1, 1, torch_input.shape[-1])

    expected = pytorch_reference(torch_input, gamma, beta)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    gamma_tt = ttnn.from_torch(
        gamma, dtype=ttnn.bfloat16, layout=ttnn.ROW_MAJOR_LAYOUT, device=device, memory_config=ttnn.DRAM_MEMORY_CONFIG
    )
    beta_tt = ttnn.from_torch(
        beta, dtype=ttnn.bfloat16, layout=ttnn.ROW_MAJOR_LAYOUT, device=device, memory_config=ttnn.DRAM_MEMORY_CONFIG
    )

    ttnn_output = layer_norm_rm(ttnn_input, gamma_tt, beta_tt)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
